import{_ as o,o as e,c as r,a2 as t}from"./chunks/framework.DnrXFDHb.js";const P=JSON.parse('{"title":"CoPoS 全產業鏈深度研究：SUMMARY","description":"","frontmatter":{},"headers":[],"relativePath":"Deep32Q知識庫/產業洞察/CoPoS/SUMMARY.md","filePath":"Deep32Q知識庫/產業洞察/CoPoS/SUMMARY.md"}'),n={name:"Deep32Q知識庫/產業洞察/CoPoS/SUMMARY.md"};function i(l,a,h,s,d,c){return e(),r("div",null,[...a[0]||(a[0]=[t('<h1 id="copos-全產業鏈深度研究-summary" tabindex="-1">CoPoS 全產業鏈深度研究：SUMMARY <a class="header-anchor" href="#copos-全產業鏈深度研究-summary" aria-label="Permalink to &quot;CoPoS 全產業鏈深度研究：SUMMARY&quot;">​</a></h1><h2 id="軸線一-技術本質" tabindex="-1">軸線一：技術本質 <a class="header-anchor" href="#軸線一-技術本質" aria-label="Permalink to &quot;軸線一：技術本質&quot;">​</a></h2><p>CoPoS 是先進封裝從圓形晶圓走向方形面板的架構升級，核心在於以面板 RDL 與更大中介層尺寸，突破 CoWoS 在超大封裝上的物理限制。玻璃基板是可能的延伸技術，可改善平整度與翹曲，但也帶來脆性、TGV 製程與可靠度等新挑戰。</p><h2 id="軸線二-台積電-copos-布局" tabindex="-1">軸線二：台積電 CoPoS 布局 <a class="header-anchor" href="#軸線二-台積電-copos-布局" aria-label="Permalink to &quot;軸線二：台積電 CoPoS 布局&quot;">​</a></h2><p>台積電已進入 CoPoS 中試線階段，並在台灣嘉義 AP7 與美國亞利桑那進行先進封裝布局。產業報導普遍將量產時程指向 2028 年底至 2029 年，但也有多個來源提醒，因翹曲與製程難度，時程仍可能調整。</p><h2 id="軸線三-台股供應鏈" tabindex="-1">軸線三：台股供應鏈 <a class="header-anchor" href="#軸線三-台股供應鏈" aria-label="Permalink to &quot;軸線三：台股供應鏈&quot;">​</a></h2><p>首波 CoPoS 台廠供應鏈包含弘塑、辛耘、均華、志聖、印能、晶彩科、大量、致茂、倍利科、家登等，橫跨濕製程、熱製程、檢測、自動化與測試。未來觀察重點在於誰拿到獨家位置與長期維護訂單。</p><h2 id="軸線四-下游需求" tabindex="-1">軸線四：下游需求 <a class="header-anchor" href="#軸線四-下游需求" aria-label="Permalink to &quot;軸線四：下游需求&quot;">​</a></h2><p>CoPoS 最大需求動能來自 AI GPU 大型化與 HBM 整合提升。NVIDIA Rubin Ultra 與 Feynman 世代被市場高度關注，若封裝尺寸持續放大，面板化平台將從選項轉為必要。</p><h2 id="軸線五-市場規模" tabindex="-1">軸線五：市場規模 <a class="header-anchor" href="#軸線五-市場規模" aria-label="Permalink to &quot;軸線五：市場規模&quot;">​</a></h2><p>整體先進封裝市場預估將在 2030 年達到 794 億美元，玻璃基板與面板封裝雖仍處早期，但中長期成長潛力明確。CoPoS 的價值不在短期營收爆發，而在於它可能打開新的封裝尺寸與材料需求空間。</p><h2 id="軸線六-競爭格局" tabindex="-1">軸線六：競爭格局 <a class="header-anchor" href="#軸線六-競爭格局" aria-label="Permalink to &quot;軸線六：競爭格局&quot;">​</a></h2><p>CoPoS 的競爭是台積電與台灣供應鏈，對上 Intel 玻璃基板與 Samsung FOPLP 的多方角力。OSAT 可能在溢出訂單與中高端應用受惠，但最先吃到頂級 AI 訂單的，仍可能是台積電與其直接供應鏈。</p><h2 id="軸線七-風險與不確定性" tabindex="-1">軸線七：風險與不確定性 <a class="header-anchor" href="#軸線七-風險與不確定性" aria-label="Permalink to &quot;軸線七：風險與不確定性&quot;">​</a></h2><p>CoPoS 目前最大風險在於翹曲、良率、設備交期、客戶集中度與地緣政治。技術仍在驗證階段，時程、滲透率與受惠程度都可能隨產業進展而改變，因此應以官方公告為主要判斷基準。</p>',15)])])}const S=o(n,[["render",i]]);export{P as __pageData,S as default};
